const body = $input.first().json.body;

if (body.fromMe === true) throw new Error('SKIP: mensagem enviada pelo bot');
if (!body.text?.message) throw new Error('SKIP: mensagem sem texto (midia/evento)');

const telefone = (body.phone || '').toString().replace(/\D/g, '');
const nome = (body.senderName || body.chatName || 'Lead').toString();
const mensagem = body.text.message.toString().trim();
const timestamp = new Date().toISOString();

if (!telefone) throw new Error('Telefone nao encontrado: ' + JSON.stringify(body));

return [{ json: { telefone, nome, mensagem, timestamp } }];

const { telefone, nome, mensagem, timestamp } = $('Extrai Dados Webhook').first().json;
const sheetsData = $('Busca Lead no Sheets').first().json;
const isNovoLead = !sheetsData.Telefone;

const promptTemplate = $('Busca Prompt GitHub').first().json.data;
const config = JSON.parse($('Busca Config GitHub').first().json.data);
const tabelaDescontos = config.descontos;
const links = config.links;

let leadData;
let historico = [];

if (!isNovoLead) {
  leadData = sheetsData;
  try { historico = JSON.parse(leadData.Historico || '[]'); } catch(e) { historico = []; }
} else {
  leadData = {
    Telefone: telefone, Nome: nome, Cidade: '', Estado: '', Concessionaria: '',
    ValorConta: '', Desconto: '', EconomiaEstimada: '', Status: 'Novo Lead',
    ScriptAtivo: 'A', FaixaAtiva: '', Historico: '[]', FollowupCount: '0',
    LinkEnviado: 'false', UltimoContato: timestamp, ProximoFollowup: '', CriadoEm: timestamp
  };
}

historico.push({ role: 'user', content: mensagem });
if (historico.length > 50) historico = historico.slice(-50);

const faixaAtiva = leadData.FaixaAtiva ? parseInt(leadData.FaixaAtiva) : null;
const estadoAtual = leadData.Estado || '';
const infoEstado = tabelaDescontos[estadoAtual] || null;
const descontoAtual = (infoEstado && faixaAtiva) ? (infoEstado.faixas[faixaAtiva] || null) : null;

const systemPrompt = [
  promptTemplate,
  '',
  'TABELA DE DESCONTOS: ' + JSON.stringify(tabelaDescontos),
  'LINKS: Faixa 1: ' + links['1'] + ' | Faixa 2: ' + links['2'] + ' | Faixa 3: ' + links['3'],
  '',
  'DADOS DO LEAD',
  'Nome: ' + (leadData.Nome || nome),
  'Cidade: ' + (leadData.Cidade || 'nao informada'),
  'Estado: ' + (estadoAtual || 'nao informado'),
  'Valor da Conta: ' + (leadData.ValorConta ? 'R$' + leadData.ValorConta : 'nao informado'),
  'Faixa ativa: ' + (faixaAtiva || 'nao definida'),
  'Desconto atual: ' + (descontoAtual ? descontoAtual + '%' : 'nao definido'),
  'Status: ' + leadData.Status,
  'Script ativo: ' + leadData.ScriptAtivo
].join('\n');

return [{
  json: {
    ...leadData,
    Telefone: telefone,
    Nome: nome || leadData.Nome,
    UltimoContato: timestamp,
    isNovoLead,
    historico,
    systemPrompt,
    links,
    tabelaDescontos
  }
}];

const leadData = $('Prepara Contexto Claude').first().json;
const response = $input.first().json;
const rawText = response.content[0].text.trim();

const tabelaDescontos = leadData.tabelaDescontos || {};

let parsed;
try {
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  const cleaned = jsonMatch ? jsonMatch[0] : rawText;
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = {
    resposta: rawText,
    status: leadData.Status || 'Em Qualificacao',
    cidade: leadData.Cidade || null,
    estado: leadData.Estado || null,
    valor_conta: null,
    economia_estimada: null,
    script_ativo: leadData.ScriptAtivo || 'A',
    faixa_ativa: leadData.FaixaAtiva ? parseInt(leadData.FaixaAtiva) : null,
    encaminhar_humano: false,
    link_enviado: false
  };
}

const historico = leadData.historico || [];
historico.push({ role: 'assistant', content: parsed.resposta });

const agora = new Date();
const proximoFollowup24h = new Date(agora.getTime() + 24 * 60 * 60 * 1000).toISOString();
const statusFinal = parsed.encaminhar_humano ? 'Aguardando Humano' : (parsed.status || leadData.Status);

// Bug 2: ScriptAtivo travado em B quando já era B
const scriptAtivo = leadData.ScriptAtivo === 'B' ? 'B' : (parsed.script_ativo || leadData.ScriptAtivo || 'A');

// Bug 3: FollowupCount preservado
const followupCount = leadData.FollowupCount || '0';

const faixaAtiva = parsed.faixa_ativa || (leadData.FaixaAtiva ? parseInt(leadData.FaixaAtiva) : null) || '';

// Bug 4: Desconto calculado da faixa + estado
const estadoFinal = parsed.estado || leadData.Estado || '';
const infoEstado = tabelaDescontos[estadoFinal] || null;
const descontoCalculado = (infoEstado && faixaAtiva) ? (infoEstado.faixas[faixaAtiva] || null) : null;
const descontoFinal = descontoCalculado !== null ? descontoCalculado : (leadData.Desconto || '');

// Claude define concessionaria; SP nao recebe auto-fill (multiplas distribuidoras)
const concessionariaFinal = parsed.concessionaria
  || (infoEstado && estadoFinal !== 'SP' ? infoEstado.concessionaria : null)
  || leadData.Concessionaria
  || '';

const links = leadData.links || {
  1: 'https://contaenergia.hiveglobal.com.br/?planId=d8fe77ecc3299e92&sellerId=lucianomiyake',
  2: 'https://contaenergia.hiveglobal.com.br/?planId=22f5eae2411265ef&sellerId=lucianomiyake',
  3: 'https://contaenergia.hiveglobal.com.br/?planId=de9ef5b8d2eeaae8&sellerId=lucianomiyake'
};

const dadosAtualizados = {
  Telefone: leadData.Telefone,
  Nome: leadData.Nome,
  Cidade: parsed.cidade || leadData.Cidade || '',
  Estado: estadoFinal,
  Concessionaria: concessionariaFinal,
  ValorConta: parsed.valor_conta || leadData.ValorConta || '',
  Desconto: descontoFinal,
  EconomiaEstimada: parsed.economia_estimada || leadData.EconomiaEstimada || '',
  Status: statusFinal,
  ScriptAtivo: scriptAtivo,
  FaixaAtiva: faixaAtiva.toString(),
  Historico: JSON.stringify(historico),
  FollowupCount: followupCount,
  LinkEnviado: parsed.link_enviado ? 'true' : (leadData.LinkEnviado || 'false'),
  UltimoContato: agora.toISOString(),
  const statusesSemFollowup = ['Cliente Ativo', 'Licenciado Ativo', 'Perdido', 'Aguardando Humano', 'Call Agendada'];
  ProximoFollowup: statusesSemFollowup.includes(statusFinal) ? '' : proximoFollowup24h,
  CriadoEm: leadData.CriadoEm || agora.toISOString()
};

const emailFinal = parsed.email || leadData.Email || '';

return [{
  json: {
    ...dadosAtualizados,
    Email: emailFinal,
    respostaParaEnviar: parsed.resposta,
    isNovoLead: leadData.isNovoLead,
    encaminhar_humano: parsed.encaminhar_humano || false
  }
}];

